+        scanner_version: SOURCE_DERIVED_SCANNER_VERSION.to_string(),
+        policy_id: INVENTORY_FRESHNESS_POLICY_ID.to_string(),
+        fresh: original_hash == rescan_hash,
+        original_hash,
